const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();

app.use(express.json());

// Set secret key (replace with your own secret key)
const SECRET_KEY = 'your_secret_key_here';

// Verify token middleware
function verifyToken(req, res, next) {
  const bearerHeader = req.header('Authorization');
  if (!bearerHeader) return res.status(401).send({ message: 'Access denied. No token provided.' });

  try {
    const token = bearerHeader.split(' ')[1];
    jwt.verify(token, SECRET_KEY);
  } catch (err) {
    return res.status(403).send({ message: 'Invalid token.' });
  }

  next();
}

// Validate access tokens endpoint
app.post('/validate-token', verifyToken, (req, res) => {
  try {
    const token = req.header('Authorization').split(' ')[1];
    const decoded = jwt.verify(token, SECRET_KEY);
    return res.status(200).send({ isValid: true });
  } catch (err) {
    return res.status(403).send({ isValid: false, message: 'Invalid token.' });
  }
});

// Start server on port 3000
const PORT = 3000;
app.listen(PORT, () => console.log(`Server running at http://localhost:${PORT}`));